use criterion::{black_box, criterion_group, criterion_main, BenchmarkId, Criterion, Throughput};
use ggen_ontology_core::{sparql_generator::SparqlGenerator, triple_store::TripleStore};
use std::time::Duration;

/// Helper function to get ontology path
fn get_ontology_path(filename: &str) -> String {
    format!(
        "{}/benches/ontologies/{}",
        env!("CARGO_MANIFEST_DIR"),
        filename
    )
}

// ========== SELECT Query Benchmarks ==========

fn bench_simple_select(c: &mut Criterion) {
    let mut group = c.benchmark_group("select_simple");
    group.measurement_time(Duration::from_secs(10));
    group.warm_up_time(Duration::from_secs(2));

    // Setup: load ontology
    let store = TripleStore::new().unwrap();
    let _ = store.load_turtle(get_ontology_path("security.ttl"));

    let query = r#"
        PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
        PREFIX sec: <http://example.com/ontology/security/>

        SELECT ?control ?label
        WHERE {
            ?control a sec:SecurityControl .
            ?control rdfs:label ?label
        }
        LIMIT 10
    "#;

    group.bench_function("simple_select", |b| {
        b.iter(|| black_box(store.query_sparql(query)))
    });

    group.finish();
}

fn bench_medium_select(c: &mut Criterion) {
    let mut group = c.benchmark_group("select_medium");
    group.measurement_time(Duration::from_secs(10));

    let store = TripleStore::new().unwrap();
    let _ = store.load_turtle(get_ontology_path("security.ttl"));

    let query = r#"
        PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
        PREFIX sec: <http://example.com/ontology/security/>

        SELECT ?control ?label ?comment
        WHERE {
            ?control a sec:SecurityControl .
            ?control rdfs:label ?label .
            OPTIONAL {
                ?control rdfs:comment ?comment
            }
        }
        ORDER BY ?label
        LIMIT 20
    "#;

    group.bench_function("medium_select", |b| {
        b.iter(|| black_box(store.query_sparql(query)))
    });

    group.finish();
}

fn bench_complex_select(c: &mut Criterion) {
    let mut group = c.benchmark_group("select_complex");
    group.measurement_time(Duration::from_secs(10));

    let store = TripleStore::new().unwrap();
    let _ = store.load_turtle(get_ontology_path("security.ttl"));
    let _ = store.load_turtle(get_ontology_path("hipaa.ttl"));

    let query = r#"
        PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
        PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
        PREFIX sec: <http://example.com/ontology/security/>

        SELECT ?control ?label ?type ?hasMFA
        WHERE {
            ?control a sec:SecurityControl .
            ?control rdfs:label ?label .
            ?control a ?type .

            {
                ?control sec:requiresMFA "true"^^xsd:boolean
                BIND("true" AS ?hasMFA)
            } UNION {
                ?control sec:requiresMFA "false"^^xsd:boolean
                BIND("false" AS ?hasMFA)
            } UNION {
                ?control a sec:SecurityControl
                FILTER NOT EXISTS { ?control sec:requiresMFA ?any }
                BIND("unknown" AS ?hasMFA)
            }

            FILTER (?type != rdf:Property)
        }
        ORDER BY DESC(?hasMFA) ?label
        LIMIT 50
    "#;

    group.bench_function("complex_select", |b| {
        b.iter(|| black_box(store.query_sparql(query)))
    });

    group.finish();
}

