// ========== Mixed Workload ==========

fn bench_mixed_workload(c: &mut Criterion) {
    let mut group = c.benchmark_group("mixed_workload");
    group.measurement_time(Duration::from_secs(15));

    let store = TripleStore::new().unwrap();
    let _ = store.load_turtle(get_ontology_path("security.ttl"));

    let select_query = r#"
        PREFIX sec: <http://example.com/ontology/security/>
        SELECT ?control WHERE { ?control a sec:SecurityControl } LIMIT 10
    "#;

    let ask_query = r#"
        PREFIX sec: <http://example.com/ontology/security/>
        ASK { ?control a sec:AuthenticationControl }
    "#;

    let construct_query = r#"
        PREFIX sec: <http://example.com/ontology/security/>
        CONSTRUCT { ?s ?p ?o } WHERE { ?s ?p ?o } LIMIT 5
    "#;

    group.bench_function("mixed_queries", |b| {
        b.iter(|| {
            black_box(store.query_sparql(select_query));
            black_box(store.query_sparql(ask_query));
            black_box(store.query_sparql(construct_query));
        })
    });

    group.finish();
}

// ========== Concurrent Execution ==========

fn bench_concurrent_queries(c: &mut Criterion) {
    use std::sync::Arc;
    use std::thread;

    let mut group = c.benchmark_group("concurrent");
    group.measurement_time(Duration::from_secs(5));

    for thread_count in [1, 2, 4, 8].iter() {
        group.bench_with_input(
            BenchmarkId::new("concurrent_queries", thread_count),
            thread_count,
            |b, &thread_count| {
                b.iter(|| {
                    let store = Arc::new(TripleStore::new().unwrap());
                    let _ = store.load_turtle(get_ontology_path("security.ttl"));

                    let query = r#"
                        PREFIX sec: <http://example.com/ontology/security/>
                        SELECT ?control WHERE { ?control a sec:SecurityControl } LIMIT 10
                    "#;

                    let handles: Vec<_> = (0..thread_count)
                        .map(|_| {
                            let store_clone = Arc::clone(&store);
                            let query = query.to_string();
                            thread::spawn(move || black_box(store_clone.query_sparql(&query)))
                        })
                        .collect();

                    for handle in handles {
                        let _ = handle.join();
                    }
                })
            },
        );
    }

    group.finish();
}

// ========== Scaling with Result Set Size ==========

fn bench_result_set_scaling(c: &mut Criterion) {
    let mut group = c.benchmark_group("result_set_scaling");
    group.measurement_time(Duration::from_secs(10));

    let store = TripleStore::new().unwrap();
    let _ = store.load_turtle(get_ontology_path("security.ttl"));

    for limit in [10, 50, 100, 500].iter() {
        group.throughput(Throughput::Elements(*limit as u64));

        group.bench_with_input(BenchmarkId::from_parameter(*limit), limit, |b, limit| {
            let query = format!(
                r#"
                        PREFIX sec: <http://example.com/ontology/security/>
                        SELECT ?control ?label WHERE {{
                            ?control a sec:SecurityControl .
                            ?control rdfs:label ?label
                        }}
                        LIMIT {}
                    "#,
                limit
            );

            b.iter(|| black_box(store.query_sparql(&query)))
        });
    }

    group.finish();
}

